-- ============================================================
-- Tabla: contratos_somos_propiedad
-- Origen: BD-CONTRATOS-SOMOS-PROPIEDAD-20260519.csv
-- Exclusiva para contabilidad del panel propietario.
-- NO depende de la tabla `proprieter`.
-- ============================================================

CREATE TABLE IF NOT EXISTS `contratos_somos_propiedad` (
  `no_contrato`         INT            NOT NULL,
  `direccion`           VARCHAR(200)   NOT NULL,
  `ciudad`              VARCHAR(60)    NOT NULL,
  `vr_canon`            DECIMAL(15,2)  NOT NULL DEFAULT 0,
  `vr_administracion`   DECIMAL(15,2)  NOT NULL DEFAULT 0,
  `valor_iva`           DECIMAL(15,2)  NOT NULL DEFAULT 0,
  `canon_total`         DECIMAL(15,2)  NOT NULL DEFAULT 0,
  `propietario`         VARCHAR(150)   NOT NULL,
  `cedula_propietario`  VARCHAR(20)    NOT NULL,
  `arrendatario`        VARCHAR(150)   NOT NULL,
  `cedula_arrendatario` VARCHAR(20)    NOT NULL,
  `aseguradora`         VARCHAR(80)    NOT NULL,
  `no_solicitud`        VARCHAR(20)    NOT NULL,
  `multiple`            ENUM('Si','No') NOT NULL DEFAULT 'No',
  PRIMARY KEY (`no_contrato`),
  INDEX `idx_cedula_prop`  (`cedula_propietario`),
  INDEX `idx_cedula_arrend` (`cedula_arrendatario`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

